<?php require 'auth.php'; require_login(); $msg=''; if($_POST){ $pass=$_POST['password']??''; if(strlen($pass)<8){$msg='Password must be minimum 8 characters';} else { $u=users(); $u['users'][0]['email']=$_POST['email']; $u['users'][0]['password_hash']=password_hash($pass, PASSWORD_DEFAULT); file_put_contents(ROOT.'/data/users.json', json_encode($u, JSON_PRETTY_PRINT)); $msg='Login updated successfully'; } } $u=users()['users'][0]; ?>
